import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const h=JSON.parse('{"title":"好感度システム","description":"","frontmatter":{},"headers":[],"relativePath":"ja/systems/affinity.md","filePath":"ja/systems/affinity.md","lastUpdated":1775394001000}'),n={name:"ja/systems/affinity.md"};function s(i,t,r,y,x,g){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="好感度システム" tabindex="-1">好感度システム <a class="header-anchor" href="#好感度システム" aria-label="Permalink to &quot;好感度システム&quot;">​</a></h1><p>キャラクターとの絆を深める好感度システムについて解説します。</p><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><p>各キャラクターには好感度レベル（Lv.1〜Lv.10）があり、好感度を上げることでキャラストーリーの解放やステータスボーナスが得られます。</p><h2 id="好感度の上げ方" tabindex="-1">好感度の上げ方 <a class="header-anchor" href="#好感度の上げ方" aria-label="Permalink to &quot;好感度の上げ方&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方法</th><th style="text-align:center;">獲得好感度</th><th style="text-align:left;">備考</th></tr></thead><tbody><tr><td style="text-align:left;">パーティに編成して戦闘</td><td style="text-align:center;">+5/戦闘</td><td style="text-align:left;">デイリー上限あり（100/日）</td></tr><tr><td style="text-align:left;">贈り物を渡す</td><td style="text-align:center;">+20〜100</td><td style="text-align:left;">キャラの好みにより変動</td></tr><tr><td style="text-align:left;">好感度イベントをクリア</td><td style="text-align:center;">+50</td><td style="text-align:left;">特定条件で発生</td></tr><tr><td style="text-align:left;">基地で交流</td><td style="text-align:center;">+10/回</td><td style="text-align:left;">1日3回まで</td></tr><tr><td style="text-align:left;">誕生日プレゼント</td><td style="text-align:center;">+200</td><td style="text-align:left;">年1回、キャラの誕生日に</td></tr></tbody></table><h2 id="好感度レベルと報酬" tabindex="-1">好感度レベルと報酬 <a class="header-anchor" href="#好感度レベルと報酬" aria-label="Permalink to &quot;好感度レベルと報酬&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">レベル</th><th style="text-align:center;">必要好感度</th><th style="text-align:left;">解放コンテンツ</th></tr></thead><tbody><tr><td style="text-align:center;">Lv.1</td><td style="text-align:center;">0</td><td style="text-align:left;">初期状態</td></tr><tr><td style="text-align:center;">Lv.2</td><td style="text-align:center;">100</td><td style="text-align:left;">キャラストーリー第1話、ステータス+1%</td></tr><tr><td style="text-align:center;">Lv.3</td><td style="text-align:center;">300</td><td style="text-align:left;">ボイス追加、ステータス+2%</td></tr><tr><td style="text-align:center;">Lv.4</td><td style="text-align:center;">600</td><td style="text-align:left;">キャラストーリー第2話、プロフィール情報追加</td></tr><tr><td style="text-align:center;">Lv.5</td><td style="text-align:center;">1,000</td><td style="text-align:left;">専用称号解放、ステータス+3%</td></tr><tr><td style="text-align:center;">Lv.6</td><td style="text-align:center;">1,500</td><td style="text-align:left;">キャラストーリー第3話</td></tr><tr><td style="text-align:center;">Lv.7</td><td style="text-align:center;">2,200</td><td style="text-align:left;">ボイス追加、ステータス+4%</td></tr><tr><td style="text-align:center;">Lv.8</td><td style="text-align:center;">3,000</td><td style="text-align:left;">キャラストーリー第4話（SSR）/最終話（SR）、ボイス解放</td></tr><tr><td style="text-align:center;">Lv.9</td><td style="text-align:center;">4,000</td><td style="text-align:left;">専用ホーム背景、ステータス+5%</td></tr><tr><td style="text-align:center;">Lv.10</td><td style="text-align:center;">5,500</td><td style="text-align:left;">キャラストーリー最終話（SSR）、限定スキン、ステータス+6%</td></tr></tbody></table><h2 id="贈り物システム" tabindex="-1">贈り物システム <a class="header-anchor" href="#贈り物システム" aria-label="Permalink to &quot;贈り物システム&quot;">​</a></h2><p>キャラクターごとに好みの贈り物カテゴリが設定されています。</p><h3 id="贈り物カテゴリ" tabindex="-1">贈り物カテゴリ <a class="header-anchor" href="#贈り物カテゴリ" aria-label="Permalink to &quot;贈り物カテゴリ&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">カテゴリ</th><th style="text-align:left;">アイテム例</th><th style="text-align:left;">入手先</th></tr></thead><tbody><tr><td style="text-align:left;">花束</td><td style="text-align:left;">野の花束、輝く花束、永遠の花束</td><td style="text-align:left;">ショップ、イベント</td></tr><tr><td style="text-align:left;">書物</td><td style="text-align:left;">古い日記、魔導書、禁断の書</td><td style="text-align:left;">ショップ、素材ステージ</td></tr><tr><td style="text-align:left;">食べ物</td><td style="text-align:left;">手作りパン、高級スイーツ、伝説のフルコース</td><td style="text-align:left;">基地の厨房で製作</td></tr><tr><td style="text-align:left;">宝飾品</td><td style="text-align:left;">銀のブローチ、宝石のペンダント、星の冠</td><td style="text-align:left;">ショップ、チャレンジ報酬</td></tr><tr><td style="text-align:left;">想い出の品</td><td style="text-align:left;">写真、記憶のオルゴール、忘却の花</td><td style="text-align:left;">イベント限定</td></tr></tbody></table><h3 id="キャラクター別好みの贈り物" tabindex="-1">キャラクター別好みの贈り物 <a class="header-anchor" href="#キャラクター別好みの贈り物" aria-label="Permalink to &quot;キャラクター別好みの贈り物&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">キャラクター</th><th style="text-align:left;">大好き（×3倍）</th><th style="text-align:left;">好き（×2倍）</th><th style="text-align:left;">普通（×1倍）</th></tr></thead><tbody><tr><td style="text-align:left;"><span class="rarity-ssr">ルシェル</span></td><td style="text-align:left;">花束</td><td style="text-align:left;">想い出の品</td><td style="text-align:left;">その他</td></tr><tr><td style="text-align:left;"><span class="rarity-ssr">ノワール</span></td><td style="text-align:left;">書物</td><td style="text-align:left;">宝飾品</td><td style="text-align:left;">その他</td></tr><tr><td style="text-align:left;"><span class="rarity-ssr">エンバー</span></td><td style="text-align:left;">食べ物</td><td style="text-align:left;">宝飾品</td><td style="text-align:left;">その他</td></tr><tr><td style="text-align:left;"><span class="rarity-ssr">セレスティア</span></td><td style="text-align:left;">書物</td><td style="text-align:left;">花束</td><td style="text-align:left;">その他</td></tr></tbody></table><p><em>その他のキャラクターの好みは準備中...</em></p><div class="tip custom-block"><p class="custom-block-title">ヒント</p><p>「大好き」カテゴリの贈り物を渡すと好感度が3倍になります。ショップで購入する前にキャラの好みを確認しましょう。</p></div><h2 id="好感度イベント" tabindex="-1">好感度イベント <a class="header-anchor" href="#好感度イベント" aria-label="Permalink to &quot;好感度イベント&quot;">​</a></h2><p>特定の好感度レベルに到達すると、基地で特別なイベントが発生します。</p><ul><li>イベントでは選択肢が表示される場合があります</li><li>正しい選択をすると追加の好感度ボーナスが得られます</li><li>イベントは一度見ると「回想」メニューからいつでも再生可能</li></ul><div class="warning custom-block"><p class="custom-block-title">注意</p><p>好感度イベントの選択肢による好感度変動は微量です。ストーリーの好みで選んでも大きな影響はありません。</p></div><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./../story/character-stories.html">キャラストーリー</a></li><li><a href="./base.html">基地システム</a></li><li><a href="./../characters/">キャラクター図鑑</a></li></ul>',22)])])}const c=e(n,[["render",s]]);export{h as __pageData,c as default};
